checker_dsl:
EXISTS (`format string argument FSA`) {
  AND {
    EXISTS (`method call MC`) {
      AND {
        (`MC is a StringFormat call`),
        (`FSA is the format argument of MC`)
      }
    },
    EXISTS (`taint source TS`) {
      AND {
        (`TS is a user-provided value source`),
        EXISTS (`taint flow path P`) {
          AND {
            (`P starts from TS`),
            (`P ends at FSA`),
            (`P does not pass through nodes with numeric or boolean types`)
          }
        }
      }
    }
  }
}
